import { type } from "arktype";
import { Product } from "./types.js";

const productSchema = type.declare<Product>()({
  id: "string",
  sku: "string",
  price: "number",
  tags: "string[]"
});

export default productSchema;

import { type } from "arktype";
import { Product } from "./types.js";

const brokenSchema = type.declare<Product>()({
  id: "string",
  sku: "string",
  price: "number"
});

export default brokenSchema;

import { type } from "arktype";
import productSchema from "./schema.js";

const payload = {
  id: "prod-88",
  sku: "SKU-999",
  price: 19.99,
  tags: ["electronics", "gadget"]
};

const result = productSchema(payload);

if (result instanceof type.errors) {
  console.error("Validation failed:", result.summary);
  process.exit(1);
} else {
  console.log(`Validated product: ${result.id}`);
}

